import React, { useContext } from 'react'
import { Link } from 'react-router-dom'
import logo from '../img/logo/logo.png'
import Button from './Button'
import { OverlayContext } from '../context/OverlayContext'

export default function HeaderBottom() {
    const { toggle } = useContext(OverlayContext)

    return (
        <div className={`container flex justify-between mx-auto items-center`}>
            <div className='py-[5px] px-[15px]'>
                <Link to='/'>
                    <img src={logo} alt='logo' className='max-sm:w-3/4 w-72' />
                </Link>
                <div className='mb-2 text-[18px]'>
                    <h5 className='inline-block'>An Internship Hub </h5> <span className='hidden sm:inline-block'>|</span> <h5 className='inline-block'>Microsoft Official Partner</h5>
                </div>
            </div>
            <div className='flex'>
                <div className='hidden md:block mr-10'>
                    <Button text='login' />
                </div>
                <div className='w-20 mr-5'>
                    <span className='text-[30px] float-right cursor-pointer' onClick={() => toggle()}>☰</span>
                </div>
            </div>
        </div>
    )
}
